import * as React from 'react';
import { useLoader, useThree } from '@react-three/fiber';
import { DataTexture, RedFormat, FloatType, RGBAFormat, LuminanceFormat, UnsignedByteType, NearestFilter, PlaneGeometry, ShaderMaterial, Vector2, DoubleSide } from 'three';
import { useMemo } from 'react';
import { buildHeatmapGrid, type MockDataset } from '@mms/domain';
import { usePlanningSelector } from '../state/world-machine';
import heatFrag from '../shaders/heatmap.glsl?raw';

export function MacroLayer(){
  const dataset = usePlanningSelector(s => s.schedule.dataset) as MockDataset;
  const grid = React.useMemo(() => buildHeatmapGrid(dataset, 4096), [dataset]);

  const texture = React.useMemo(() => {
    const tex = new DataTexture(grid.data as unknown as Uint8Array<ArrayBuffer>, grid.width, grid.height, LuminanceFormat, UnsignedByteType);
    tex.needsUpdate = true; tex.magFilter = NearestFilter; tex.minFilter = NearestFilter;
    return tex;
  }, [grid]);

  const material = React.useMemo(() => new ShaderMaterial({
    uniforms: {
      uTex: { value: texture },
      uTexSize: { value: new Vector2(grid.width, grid.height) },
      uViewport: { value: new Vector2(1,1) },
    },
    vertexShader: `varying vec2 vUv; void main(){ vUv = uv; gl_Position = projectionMatrix * modelViewMatrix * vec4(position,1.0); }`,
    fragmentShader: heatFrag,
    transparent: false,
    side: DoubleSide,
  }), [texture]);

  const geometry = React.useMemo(() => new PlaneGeometry(1, 1, 1, 1), []);

  return (
    <mesh geometry={geometry} material={material} scale={[grid.width, grid.height, 1]} position={[grid.width/2, grid.height/2, 0]} />
  );
}

