    11→function buildSpatialIndex(rects: {x:number;y:number;w:number;h:number;idx:number}[], cellSize=32){
    12→  const grid = new Map<string, SpatialCell>();
    13→  function key(cx:number,cy:number){ return `${cx},${cy}`; }
    14→  for(const r of rects){
    15→    const x0 = Math.floor(r.x/cellSize), y0=Math.floor(r.y/cellSize);
    16→    const x1 = Math.floor((r.x+r.w)/cellSize), y1=Math.floor((r.y+r.h)/cellSize);
    17→    for(let cy=y0; cy<=y1; cy++) for(let cx=x0; cx<=x1; cx++){
    18→      const k = key(cx,cy);
    19→      let cell = grid.get(k); if(!cell){ cell={indices:[]}; grid.set(k,cell); }
    20→      cell.indices.push(r.idx);
