import * as React from 'react';
import { InstancedMesh, BoxGeometry, MeshBasicMaterial, Color, InstancedBufferAttribute, Matrix4, DynamicDrawUsage } from 'three';
import { useThree } from '@react-three/fiber';
import { usePlanningSelector, PlanningActions } from '../state/world-machine';
import type { MockDataset } from '@mms/domain';

const MAX_INSTANCES = 60000;

type SpatialCell = { indices: number[] };

function buildSpatialIndex(rects: {x:number;y:number;w:number;h:number;idx:number}[], cellSize=32){
  const grid = new Map<string, SpatialCell>();
  function key(cx:number,cy:number){ return `${cx},${cy}`; }
  for(const r of rects){
    const x0 = Math.floor(r.x/cellSize), y0=Math.floor(r.y/cellSize);
    const x1 = Math.floor((r.x+r.w)/cellSize), y1=Math.floor((r.y+r.h)/cellSize);
    for(let cy=y0; cy<=y1; cy++) for(let cx=x0; cx<=x1; cx++){
      const k = key(cx,cy);
      let cell = grid.get(k); if(!cell){ cell={indices:[]}; grid.set(k,cell); }
      cell.indices.push(r.idx);
    }
  }
  return { cellSize, grid, key };
}

export function MesoLayer(){
  const dataset = usePlanningSelector(s => s.schedule.dataset) as MockDataset;
  const viewport = usePlanningSelector(s => s.viewport);
  const hoveredId = usePlanningSelector(s => s.selection.hoveredId as string|null);

  const meshRef = React.useRef<InstancedMesh>(null!);
  const mat = React.useMemo(() => new MeshBasicMaterial({ vertexColors: true }), []);
  const geom = React.useMemo(() => new BoxGeometry(1,1,1), []);

  // Prepare instance transforms & colors
  const rectangles = React.useMemo(() => {
    const list: {x:number;y:number;w:number;h:number;idx:number;id:string}[] = [];
    let idx = 0;
    for(const t of dataset.tasks){
      if(idx>=MAX_INSTANCES) break;
      const w = Math.max(2, (t.end - t.start) / (24*60*60*1000));
      const x = (t.start - dataset.startTime) / (24*60*60*1000);
      const y = dataset.trains.findIndex(tr => tr.id===t.trainId) * 2;
      list.push({ x, y, w, h:1.5, idx, id: t.id });
      idx++;
    }
    return list;
  }, [dataset]);

  const index = React.useMemo(()=>buildSpatialIndex(rectangles, 16),[rectangles]);

  React.useEffect(() => {
    const mesh = meshRef.current;
    const colorArray = new Float32Array(rectangles.length * 3);
    const matrix = new Matrix4();

    rectangles.forEach((r, i) => {
      matrix.setPosition(r.x + r.w/2, r.y, 0);
      matrix.scale({ x: r.w, y: r.h, z: 1 } as any);
      mesh.setMatrixAt(i, matrix);
      const col = new Color(r.w>6 ? '#f59e0b' : '#1d4ed8');
      colorArray.set([col.r, col.g, col.b], i*3);
    });

    mesh.instanceColor = new InstancedBufferAttribute(colorArray, 3);
    mesh.instanceColor.usage = DynamicDrawUsage;
    mesh.count = rectangles.length;
    mesh.instanceMatrix.needsUpdate = true;
  }, [rectangles]);

  // hover picking via spatial hash
  React.useEffect(() => {
    function pick(clientX:number, clientY:number){
      const rect = (document.getElementById('gl-root') as HTMLDivElement).getBoundingClientRect();
      const x = clientX - rect.left; const y = clientY - rect.top;
      // simple mapping as we use world units ~= days/rows
      const cx = Math.floor(x/16), cy=Math.floor(y/16);
      const cell = index.grid.get(index.key(cx,cy));
      if(!cell) return null;
      return cell.indices[0] ?? null;
    }

    function onMove(ev: PointerEvent){
      const idx = pick(ev.clientX, ev.clientY);
      if(idx==null) return;
      const id = rectangles[idx]?.id ?? null;
      PlanningActions.selection.setHovered(id);
      const mesh = meshRef.current; if(!mesh.instanceColor) return;
      // highlight by rewriting color in GPU buffer (single element) - use setXYZ for RGB
      const arr = mesh.instanceColor.array as Float32Array;
      arr[idx * 3 + 0] = 1.0; // R
      arr[idx * 3 + 1] = 1.0; // G
      arr[idx * 3 + 2] = 0.0; // B (yellow highlight)
      mesh.instanceColor.needsUpdate = true;
    }

    const root = document.getElementById('gl-root')!;
    root.addEventListener('pointermove', onMove);
    return () => root.removeEventListener('pointermove', onMove);
  }, [index, rectangles]);

  return (
    <instancedMesh ref={meshRef} args={[geom, mat, Math.min(MAX_INSTANCES, rectangles.length)]} />
  );
}

